var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"이거 미안하게 됐군.","JPN":"君には悪いことをしてしまった。","ENG":"I must apologize for this.","TWN":"我必須向你道歉，克萊爾小姐。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 자네의 관심을 사려면 이 방법이 가장 확실하다고 생각했거든.","JPN":"だが、君の興味を引くにはこの手が一番手っ取り早いと思ったのだよ。","ENG":"But it was the surest way of getting your attention.","TWN":"不過，我認為這是最能引起你興趣的方法。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"무엇보다도 우리에게 주어진 시간이 그리 많지 않아서 말이야.","JPN":"なにより、私たちにはあまり時間がないものでね。","ENG":"You see, we don't have much time.","TWN":"最重要的是，我們的時間不多了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"방식이 다소 무례하더라도 부디 이해해 주길 바라네.","JPN":"無礼なやり方をしてしまったが、どうか理解してほしい。","ENG":"I hope you understand, even if my methods were rash.","TWN":"方式有些無禮，還請見諒。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"……하아.","JPN":"……はあ。","ENG":"...*Sigh*","TWN":"……哈啊。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"허례허식은 집어치우세요.","JPN":"正直に答えてください。","ENG":"Enough with the pretentiousness.","TWN":"別說客套話了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어디까지 알고 있죠? 그분께서 보낸 사람인가요?","JPN":"どこまで知っているのですか？　あの人の使いで来たのですか？","ENG":"How much do you know? Did that person send you to me?","TWN":"你到底知道多少？是那位派你來的嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Haha.","TWN":"……呵呵。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 그럴 리는 없겠네요. 만약 그랬으면 편지를 빼앗긴 시점에서 전 살해당했을 테니까.","JPN":"いや、違いますね。もしそうだったら、手紙を奪われた時点で私は殺されていたはず。","ENG":"No, that can't be right. Because that would mean that I'd already be dead by the time it was stolen from me.","TWN":"不，不太可能。如果真是那樣的話，我在信被搶走的那一刻就已經被殺了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 대체 당신은 정체가 뭔가요? 저한테 뭘 원하는 거죠?","JPN":"ではあなたの望みは何ですか？　あなたは誰なんですか？","ENG":"Then, who are you? What do you want from me?","TWN":"那你到底是誰？你想從我這裡得到什麼？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"전에 봤을 때의 우아한 태도는 온데간데없군.","JPN":"前回の優雅な態度が嘘のようだな。","ENG":"Your graceful attitude I saw before seems to have gone away.","TWN":"之前看到的優雅態度已經不復在了。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 연기를 하지 않는 자네의 원래 성격인가?","JPN":"それが、役を演じていない素の君なのかね？","ENG":"Is this your true personality?","TWN":"這就是你不演戲時的本性嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요, 모두가 타인을 대할 때 적당한 가면을 고르지 않나요?","JPN":"さあ、誰しも他人と向き合う時は、相応の仮面を被るものでしょう。","ENG":"Well, doesn't everyone choose an appropriate mask when dealing with other people?","TWN":"呵，大家在面對別人時不都會選擇戴上合適的面具嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"비슷한 거예요. 상대방이 원하는 배역을 연기해주면, 바라는 걸 쉽게 얻을 수 있으니까.","JPN":"それと同じです。相手の望む役を演じてあげれば、こちらも目的を果たすのは容易い。","ENG":"Let's say it's something similar. Because it's easier to get what I want if I play the role others expect.","TWN":"只要演好對方期望的角色，就能輕鬆得到自己想要的東西。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"타인에게 완벽히 솔직한 사람은 없어요. 다들 적당히 속고, 속이며 살죠.","JPN":"他人に本当の自分をさらけ出す人などいません。皆適当にだまし、だまされて生きているんです。","ENG":"Nobody is completely honest with others. They all cheat and deceive one another.","TWN":"沒有人會對他人完全坦誠，大家都在恰如其分的欺騙和被欺騙中生活。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"당신에겐, 그저 연기할 가치조차 못 느낄 뿐.","JPN":"あなたには、演技する価値すら感じていないだけ。","ENG":"It's just that I don't see any reason to act in front of you.","TWN":"只是對現在的你來說，演戲並沒有什麼意義。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 곱상한 외모와는 달리 꽤나 독설가로군.","JPN":"ふふ、綺麗な顔にそぐわず、かなりの毒舌だな。","ENG":"Haha. You have quite the sharp tongue unlike that pretty face you have.","TWN":"呵呵，好一個長相貌美，口齒伶俐的女生。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래서?","JPN":"それで？","ENG":"So?","TWN":"所以呢？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"그런 식으로 왕국의 왕세자를 협박하여, 매달 큰 돈을 갈취해 온 건가?","JPN":"そんな風に皇太子を脅し、毎月大金をゆすり取っていたのか。","ENG":"Have you been threatening the prince and extorting money from him every month?","TWN":"你也是這樣威脅一位王國的王儲，每個月勒索大筆錢財的嗎？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"하! 협박이라고요?","JPN":"は！　脅すですって？","ENG":"Ha! Threaten him?","TWN":"哈！威脅他？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"안타깝게도 그 분에게 목숨을 위협받고 있는 건 오히려 저랍니다.","JPN":"残念ながら、あの方に命を脅かされているのは私のほうです。","ENG":"Unfortunately, I'm the one being threatened by him.","TWN":"可惜的是，受到生命威脅的反而是我。"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"목숨을 위협받는다라?","JPN":"命を脅かされている？","ENG":"You're being threatened?","TWN":"生命威脅？"},"stage":{"bg":"BACKSTREET3","slots":{"L":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"추정컨대, 그분께서는 평민 출신 오페라 배우와 찍은 사진이 정치적으로 발목을 잡게 될 거라고 생각하신 모양이에요.","JPN":"あの方は平民出身のオペラ女優と撮った写真が、自分の政治的な足手まといになると思っているらしくて。","ENG":"I assume that he never imagined that he would be in political danger from taking a photo with a commoner opera actress.","TWN":"他大概是認為，與平民出身的歌劇演員拍照會成為政治上的絆腳石。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"제 열렬한 팬을 자처하면서 멋대로 <color=#ffd34c>사진</color>을 찍자고 할 땐 언제고.","JPN":"自分から熱烈なファンを名乗り、私と<color=#ffd34c>写真</color>を撮ろうと言ってきたくせに。","ENG":"He's the one who said he was my biggest fan and insisted that I take a <color=#ffd34c>photo</color> with him.","TWN":"原本還自稱是我忠實粉絲的時候，硬要跟我<color=#ffd34c>合照</color>。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이제는 그 사진 때문에 자기 혼삿길이 막힐지도 모른다고 벌벌 떨더군요.","JPN":"ここにきて、あの写真のせいで自分の縁談が上手くいかないかもしれないと怯えているんです。","ENG":"He is now terrified that his chances of getting married will be ruined as a result.","TWN":"現在因為那張照片，擔心自己的婚事可能會泡湯，嚇得發抖。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"참으로 대단한 일이죠.","JPN":"まったく大層なお方ですよね。","ENG":"The nerve he has.","TWN":"真是了不起啊。"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SUITMAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET3","slots":{"L":null,"C":{"char_id":"SUITMAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};